  2→ * Protocol types for communication between the Rust core and TypeScript frontend.
  3→ *
  4→ * All messages are newline-delimited JSON over stdin/stdout. The core sends
  5→ * Request messages and receives Response messages back. Every message includes
  6→ * a protocol version for compatibility checking.
  7→ */
  8→
  9→export const PROTOCOL_VERSION = "0.1.0";
 10→export const FRONTEND_LANGUAGE = "typescript";
