 12→// ---------------------------------------------------------------------------
 13→// Request: Core → Frontend
 14→// ---------------------------------------------------------------------------
 15→
 16→export type SetupMode = "per_function" | "per_execution";
 17→
 18→export type GeneratorKind = "type_name" | "param_name";
 19→
 20→export type Command =
 21→  | "handshake"
 22→  | "analyze"
 23→  | "instrument"
 24→  | "execute"
 25→  | "setup"
 26→  | "teardown"
 27→  | "generate"
 28→  | "shutdown";
 29→
 30→export interface MockConfig {
 31→  symbol: string;
 32→  return_values: unknown[];
 33→  should_track_calls: boolean;
 34→  default_behavior: "return_generated" | "repeat_last" | "throw_error" | "passthrough";
 35→}
