 37→interface BaseRequest {
 38→  protocol_version: string;
 39→  id: number;
 40→  command: Command;
 41→}
 42→
 43→export interface HandshakeRequest extends BaseRequest {
 44→  command: "handshake";
 45→  capabilities: string[];
 46→}
 47→
 48→export interface AnalyzeRequest extends BaseRequest {
 49→  command: "analyze";
 50→  file: string;
 51→  function?: string | null;
 52→  project_root?: string | null;
 53→}
 54→
 55→export interface InstrumentRequest extends BaseRequest {
 56→  command: "instrument";
 57→  file: string;
 58→  function: string;
 59→  mocks: MockConfig[];
 60→  project_root?: string | null;
 61→}
 62→
 63→export interface ExecuteRequest extends BaseRequest {
 64→  command: "execute";
 65→  function: string;
 66→  inputs: unknown[];
 67→  mocks: MockConfig[];
 68→  setup_context?: unknown;
 69→}
 70→
 71→export interface SetupRequest extends BaseRequest {
 72→  command: "setup";
 73→  file: string;
 74→  function: string;
 75→  mode: SetupMode;
 76→  project_root?: string | null;
 77→}
 78→
 79→export interface TeardownRequest extends BaseRequest {
 80→  command: "teardown";
 81→  function: string;
 82→}
 83→
 84→export interface GenerateRequest extends BaseRequest {
 85→  command: "generate";
 86→  file: string;
 87→  name: string;
 88→  kind: GeneratorKind;
 89→  recipe?: unknown;
 90→  project_root?: string | null;
 91→}
 92→
 93→export interface ShutdownRequest extends BaseRequest {
 94→  command: "shutdown";
 95→}
 96→
 97→export type Request =
 98→  | HandshakeRequest
 99→  | AnalyzeRequest
100→  | InstrumentRequest
101→  | ExecuteRequest
102→  | SetupRequest
103→  | TeardownRequest
104→  | GenerateRequest
105→  | ShutdownRequest;
