  1→//! Build script: generates `string_ops_generated.rs` from `data/string-ops.yaml`.
  2→//!
  3→//! Validates the YAML spec (no duplicate method names, valid sorts/styles) and
  4→//! emits a `StringOp` enum with `z3_sort()`, `resolve_string_op()`, and
  5→//! sort-grouped constant arrays.
  6→
  7→use serde::Deserialize;
  8→use std::collections::{HashMap, HashSet};
  9→use std::env;
 10→use std::fs;
 11→use std::path::Path;
 12→
 13→#[derive(Deserialize)]
 14→struct Spec {
 15→    operations: Vec<Operation>,
 16→}
 17→
 18→#[derive(Deserialize)]
 19→struct Operation {
 20→    name: String,
 21→    z3_sort: String,
 22→    aliases: Vec<Alias>,
 23→}
 24→
 25→#[derive(Deserialize)]
 26→struct Alias {
 27→    // Parsed for validation completeness; not used in codegen since aliases are
 28→    // grouped by canonical operation, not by language.
 29→    #[allow(dead_code)]
 30→    language: String,
 31→    method: String,
 32→    style: String,
 33→}
 34→
 35→fn main() {
 36→    let manifest_dir = env::var("CARGO_MANIFEST_DIR").unwrap();
 37→    let yaml_path = Path::new(&manifest_dir).join("data/string-ops.yaml");
 38→    println!("cargo::rerun-if-changed={}", yaml_path.display());
 39→
 40→    let yaml_content = fs::read_to_string(&yaml_path)
 41→        .unwrap_or_else(|e| panic!("failed to read {}: {e}", yaml_path.display()));
 42→    let spec: Spec = serde_yaml::from_str(&yaml_content)
 43→        .unwrap_or_else(|e| panic!("failed to parse {}: {e}", yaml_path.display()));
 44→
 45→    validate(&spec);
 46→
 47→    let out_dir = env::var("OUT_DIR").unwrap();
 48→    let out_path = Path::new(&out_dir).join("string_ops_generated.rs");
 49→    let code = generate(&spec);
 50→    fs::write(&out_path, code)
 51→        .unwrap_or_else(|e| panic!("failed to write {}: {e}", out_path.display()));
 52→}
 53→
 54→fn validate(spec: &Spec) {
 55→    let valid_sorts = ["Bool", "Int", "Str"];
 56→    let valid_styles = ["receiver", "free"];
 57→    let mut seen_methods: HashMap<String, String> = HashMap::new();
 58→
 59→    for op in &spec.operations {
 60→        assert!(
 61→            valid_sorts.contains(&op.z3_sort.as_str()),
 62→            "operation '{}' has invalid z3_sort '{}' (expected one of {valid_sorts:?})",
 63→            op.name,
 64→            op.z3_sort,
 65→        );
 66→
 67→        for alias in &op.aliases {
 68→            assert!(
 69→                valid_styles.contains(&alias.style.as_str()),
 70→                "alias '{}' in operation '{}' has invalid style '{}' (expected one of {valid_styles:?})",
 71→                alias.method,
 72→                op.name,
 73→                alias.style,
 74→            );
 75→
 76→            if let Some(prev_op) = seen_methods.get(&alias.method) {
 77→                if prev_op != &op.name {
 78→                    panic!(
 79→                        "duplicate method name '{}': defined in both '{}' and '{}'",
 80→                        alias.method, prev_op, op.name,
 81→                    );
 82→                }
 83→                // Same operation, different language — allowed (e.g. Go "len" and Rust "len")
 84→            } else {
 85→                seen_methods.insert(alias.method.clone(), op.name.clone());
 86→            }
 87→        }
 88→    }
 89→}
