 91→fn to_pascal_case(s: &str) -> String {
 92→    s.split('_')
 93→        .map(|part| {
 94→            let mut chars = part.chars();
 95→            match chars.next() {
 96→                Some(c) => c.to_uppercase().collect::<String>() + chars.as_str(),
 97→                None => String::new(),
 98→            }
 99→        })
100→        .collect()

 1→# Canonical string operations and per-language aliases.
 2→#
 3→# Each operation maps to a Z3 Seq theory function. The `z3_sort` field
 4→# declares the Z3 sort of the operation's return value (Bool, Int, or Str).
 5→# Aliases list the method names as reported by each language frontend.
 6→
 7→operations:
 8→  - name: contains
 9→    z3_sort: Bool
10→    aliases:
11→      - { language: typescript, method: "includes",          style: receiver }
12→      - { language: go,         method: "Contains",          style: free }
13→      - { language: go,         method: "strings.Contains",  style: free }
14→      - { language: rust,       method: "contains",          style: receiver }
15→
16→  - name: prefix
17→    z3_sort: Bool
18→    aliases:
19→      - { language: typescript, method: "startsWith",        style: receiver }
20→      - { language: go,         method: "HasPrefix",         style: free }
21→      - { language: go,         method: "strings.HasPrefix", style: free }
22→      - { language: rust,       method: "starts_with",       style: receiver }
23→
24→  - name: suffix
25→    z3_sort: Bool
26→    aliases:
27→      - { language: typescript, method: "endsWith",          style: receiver }
28→      - { language: go,         method: "HasSuffix",         style: free }
29→      - { language: go,         method: "strings.HasSuffix", style: free }
30→      - { language: rust,       method: "ends_with",         style: receiver }
31→
32→  - name: index_of
33→    z3_sort: Int
34→    aliases:
35→      - { language: typescript, method: "indexOf",           style: receiver }
36→      - { language: go,         method: "Index",             style: free }
37→      - { language: go,         method: "strings.Index",     style: free }
38→      - { language: rust,       method: "find",              style: receiver }
39→
40→  - name: length
41→    z3_sort: Int
42→    aliases:
43→      - { language: typescript, method: "length",            style: receiver }
44→      - { language: go,         method: "len",               style: free }
45→      - { language: rust,       method: "len",               style: receiver }
46→
47→  - name: char_at
48→    z3_sort: Str
49→    aliases:
50→      - { language: typescript, method: "charAt",            style: receiver }
51→
52→  - name: substr
53→    z3_sort: Str
54→    aliases:
55→      - { language: typescript, method: "slice",             style: receiver }
56→      - { language: typescript, method: "substring",         style: receiver }
57→      - { language: typescript, method: "substr",            style: receiver }
58→
59→  - name: concat
60→    z3_sort: Str
61→    aliases:
62→      - { language: typescript, method: "concat",            style: receiver }
